const e={"PL-1":{title:"Policy and Procedures",body:"[ORG] has developed, documented, and disseminated a Planning Policy addressing SSP, rules of behavior, and privacy plan requirements consistent with DoDI 8510.01 and NIST SP 800-18. Reviewed annually. The [ISSM] is responsible for the planning program for [SYSTEM].",tools:[]},"PL-2":{title:"System Security and Privacy Plans",body:"[ORG] develops, documents, and maintains a System Security Plan (SSP) for [SYSTEM] describing: system boundary, security categorization, information types, operational environment, external connections, security control implementation, and personnel responsibilities. Maintained in [TOOL:emass] and reviewed annually. Approved by [AO]. The [ISSO] is responsible for SSP maintenance. Protected from unauthorized access as a sensitive document.",tools:["emass"]},"PL-4":{title:"Rules of Behavior",body:"[ORG] establishes Rules of Behavior (ROB) for [SYSTEM] covering: acceptable use, password requirements, CUI handling, incident reporting, and consequences of non-compliance. All personnel with access acknowledge and sign the ROB before account creation and annually thereafter. Signed ROBs maintained by [ISSO] for duration of access plus 3 years.",tools:[]},"PL-4(1)":{title:"Rules of Behavior | Social Media and External Site/Application Usage Policy",body:"[ORG]'s Rules of Behavior include restrictions on use of social media, social networking sites, and external web-based applications regarding [SYSTEM] information. Personnel are prohibited from discussing [SYSTEM] details on social media. CUI is never posted to social media or external web applications. [TOOL:zscaler] enforces technical controls on social media access from [SYSTEM] networks. Social media usage restrictions are enforced and violations are reported to the [ISSO].",tools:["zscaler"]},"PL-7":{title:"Concept of Operations",body:"[ORG] develops a Concept of Operations (CONOPS) for [SYSTEM] describing: system purpose, user roles, operational environment, key interfaces, data flows, and security architecture. The CONOPS is maintained in [TOOL:emass] and reviewed annually. The CONOPS documents how [TOOL:paloalto], [TOOL:crowdstrike], [TOOL:splunk], and other security tools operate to protect [SYSTEM]. The [ISSO] ensures the CONOPS accurately reflects the current security architecture.",tools:["emass","paloalto","crowdstrike","splunk"]},"PL-8":{title:"Security and Privacy Architectures",body:"[ORG] develops a security architecture for [SYSTEM] documenting: overall philosophy, requirements, and approach to protecting CUI. Architecture includes: defense-in-depth using [TOOL:paloalto] at the perimeter, [TOOL:crowdstrike] for endpoint protection, [TOOL:splunk] for monitoring, and [TOOL:cac] for authentication. The [ISSO] ensures architecture decisions are reflected in implemented controls. Architecture documented in SSP in [TOOL:emass] and reviewed annually.",tools:["emass","paloalto","crowdstrike","splunk","cac"]},"PL-8(1)":{title:"Security and Privacy Architectures | Defense in Depth",body:"[SYSTEM]'s security architecture employs a defense-in-depth approach providing multiple overlapping security capabilities to protect against various threat scenarios. Defense layers include: [TOOL:paloalto] perimeter firewall and IPS, [TOOL:zscaler] web proxy, [TOOL:ivanti] VPN, [TOOL:crowdstrike] EDR, [TOOL:hbss] AV/HIPS, [TOOL:gpo] endpoint hardening, [TOOL:cac] MFA, and [TOOL:splunk] SIEM. Each layer provides independent protection reducing reliance on any single control.",tools:["paloalto","zscaler","ivanti","crowdstrike","hbss","gpo","cac","splunk"]},"PL-9":{title:"Central Management",body:"[ORG] centrally manages [SYSTEM] security controls using automated mechanisms. [TOOL:gpo] centrally manages Windows security configuration across all endpoints. [TOOL:tenablesc] centrally manages [TOOL:acas] vulnerability scanning. [TOOL:crowdstrike] Falcon platform centrally manages endpoint protection. [TOOL:splunk] centrally manages log collection and analysis. Central management ensures consistent security control implementation and reduces configuration drift.",tools:["gpo","tenablesc","acas","crowdstrike","splunk"]},"PL-10":{title:"Baseline Selection",body:"[ORG] selects a security control baseline for [SYSTEM] commensurate with the system's security categorization. [SYSTEM] is categorized at [SECURITY CATEGORIZATION] per FIPS 199 and CNSSI 1253. The baseline control set is selected from NIST SP 800-53 Rev 5 and tailored per DoD overlays. Tailoring decisions are documented in the SSP in [TOOL:emass] and approved by [AO]. Control baseline reviewed during annual security reviews.",tools:["emass"]},"PL-11":{title:"Baseline Tailoring",body:"[ORG] tailors the selected control baseline for [SYSTEM] based on organizational and system-specific conditions. Tailoring decisions are documented in the SSP with supporting rationale approved by [AO]. DoD overlays and applicable DISA STIGs are applied as part of the tailoring process. Controls are added where organizational risk requires additional protection. Controls are removed only with [AO] approval and documented risk acceptance. Tailoring decisions reviewed annually.",tools:[]}};export{e as default};
